# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, render_template, request
import cgi

app = Flask(__name__)

@app.route('/dashboard')
def dashboard():
    user_name = request.args.get('name', 'Guest')
    user_bio = request.args.get('bio', 'No bio provided.')
    user_location = request.args.get('location', 'Unknown')
    user_status = request.args.get('status', 'Online')

    # Sanitize inputs to prevent XSS, but allow specific formatting.
    # A more robust solution might use a dedicated Markdown parser or a whitelist HTML sanitizer.
    # For this example, we'll do a simple replacement for demonstration.
    
    # Escape all HTML first
    safe_bio = cgi.escape(user_bio)
    safe_status = cgi.escape(user_status)

    # Then, allow specific formatting by replacing escaped tags with actual tags
    # This is a very basic approach and has limitations.
    # For robust production, consider libraries like bleach or markdown2.
    safe_bio = safe_bio.replace('&lt;b&gt;', '<b>').replace('&lt;/b&gt;', '</b>')
    safe_bio = safe_bio.replace('&lt;i&gt;', '<i>').replace('&lt;/i&gt;', '</i>')
    safe_bio = safe_bio.replace('&lt;em&gt;', '<em>').replace('&lt;/em&gt;', '</em>')
    safe_bio = safe_bio.replace('&lt;strong&gt;', '<strong>').replace('&lt;/strong&gt;', '</strong>')

    safe_status = safe_status.replace('&lt;b&gt;', '<b>').replace('&lt;/b&gt;', '</b>')
    safe_status = safe_status.replace('&lt;i&gt;', '<i>').replace('&lt;/i&gt;', '</i>')
    safe_status = safe_status.replace('&lt;em&gt;', '<em>').replace('&lt;/em&gt;', '</em>')
    safe_status = safe_status.replace('&lt;strong&gt;', '<strong>').replace('&lt;/strong&gt;', '</strong>')

    return render_template(
        'dashboard.html',
        name=user_name,
        bio=safe_bio,
        location=user_location,
        status=safe_status
    )

if __name__ == '__main__':
    app.run(debug=True)

